import{_ as t,a}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as n,o as s,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Hugging Face Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/huggingface.md","filePath":"my/upload/huggingface.md","lastUpdated":1781962217000}'),r={name:"my/upload/huggingface.md"};function d(c,e,l,p,g,h){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="hugging-face-channel-ထည့်သွင်းခြင်း" tabindex="-1">Hugging Face Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#hugging-face-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;Hugging Face Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><p>အချက်သုံးခုပဲလိုပါတယ်:</p><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>အသုံးပြုပုံ</th></tr></thead><tbody><tr><td>Hugging Face account</td><td>access token ဖန်တီးရန်နှင့် repository ပိုင်ရန်။</td></tr><tr><td>Hugging Face User Access Token</td><td>ImgBed က Hugging Face API ကို access လုပ်ရန်၊ repositories ဖန်တီးရန်၊ files upload လုပ်ရန်။</td></tr><tr><td>Repository name</td><td>repository name ပဲထည့်နိုင်ပါတယ်၊ ဥပမာ <code>image</code>။</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-hugging-face-ထဲ-sign-in-ဝင်ပြီး-access-token-ဖန်တီးပါ" tabindex="-1">Step 1: Hugging Face ထဲ Sign in ဝင်ပြီး Access Token ဖန်တီးပါ <a class="header-anchor" href="#step-1-hugging-face-ထဲ-sign-in-ဝင်ပြီး-access-token-ဖန်တီးပါ" aria-label="Permalink to &quot;Step 1: Hugging Face ထဲ Sign in ဝင်ပြီး Access Token ဖန်တီးပါ&quot;">​</a></h3><ol><li>Hugging Face ထဲ sign in ဝင်ပါ။</li><li>ညာဘက်အပေါ်ထောင့်က avatar ကိုနှိပ်ပြီး <code>Settings</code> ကိုဖွင့်ပါ။</li><li>left sidebar မှ <code>Access Tokens</code> ကိုဖွင့်ပါ။</li><li>token အသစ်ဖန်တီးပါ။</li><li>token ကိုမှတ်မိလွယ်တဲ့အမည်ပေးပါ။</li><li><code>write</code> permission ကိုရွေးပါ။</li><li>token ဖန်တီးပြီးတာနဲ့ ချက်ချင်း copy လုပ်ပြီးသိမ်းပါ။</li></ol><p><img src="'+t+'" alt="Create a token" loading="lazy"></p><h2 id="step-2-imgbed-မှာ-hugging-face-channel-ဖြည့်ပါ" tabindex="-1">Step 2: ImgBed မှာ Hugging Face Channel ဖြည့်ပါ <a class="header-anchor" href="#step-2-imgbed-မှာ-hugging-face-channel-ဖြည့်ပါ" aria-label="Permalink to &quot;Step 2: ImgBed မှာ Hugging Face Channel ဖြည့်ပါ&quot;">​</a></h2><p>Upload Settings မှာ <code>Hugging Face</code> ရွေးပြီးနောက် fields တွေကို ဒီလိုဖြည့်ပါ:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>ကိုယ်ရွေးတဲ့အမည်၊ ဥပမာ <code>hf-primary</code>။</td></tr><tr><td>Repository name</td><td>short repo name <code>image</code> သို့မဟုတ် full path <code>username/image</code>။</td></tr><tr><td>Access Token</td><td>မကြာသေးခင်ဖန်တီးထားတဲ့ Hugging Face User Access Token။</td></tr><tr><td>Private repository</td><td>လိုအပ်ချက်အရ on/off လုပ်ပါ။</td></tr><tr><td>Remark</td><td>optional၊ ဥပမာ <code>Primary upload channel</code>။</td></tr></tbody></table><p><img src="'+a+`" alt="Add the channel" loading="lazy"></p><h2 id="step-3-channel-save-လုပ်ပါ" tabindex="-1">Step 3: Channel Save လုပ်ပါ <a class="header-anchor" href="#step-3-channel-save-လုပ်ပါ" aria-label="Permalink to &quot;Step 3: Channel Save လုပ်ပါ&quot;">​</a></h2><p>fields ဖြည့်ပြီးနောက် Save ကိုနှိပ်ပါ။</p><p>system က ဒီအချက်တွေကို ကိုယ်တိုင် handle လုပ်ပါမယ်:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short repository name</td><td>ImgBed က current Hugging Face account ကိုသိပြီး value ကို full repository path အဖြစ် expand လုပ်သည်။</td></tr><tr><td>Full repository path</td><td><code>username/repository</code> path ကို ထည့်ထားတဲ့အတိုင်းသုံးသည်။</td></tr><tr><td>Repository check</td><td>current personal account path ဖြစ်လျှင် repository မရှိသောအခါ create လုပ်ရန်ကြိုးစားသည်။ full path ကို manual ထည့်ထားလျှင် အဲဒီ path ကိုပဲသုံးသည်။</td></tr><tr><td>Repository type</td><td>ဒီ channel က <code>dataset</code> repository ကိုသုံးသည်။</td></tr><tr><td>Public/private state</td><td>repository visibility ကို current switch အတိုင်း synchronized လုပ်သည်။</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face ထဲ sign in ဝင်ပါ</span></span>
<span class="line"><span>-&gt; Access Token ဖန်တီးပါ</span></span>
<span class="line"><span>-&gt; write permission ရွေးပါ</span></span>
<span class="line"><span>-&gt; ImgBed ကိုပြန်သွားပြီး token နဲ့ repository name ထည့်ပါ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; repo name ပဲထည့်ထားရင် ImgBed က current username ကိုအလိုအလျောက်ထည့်ပါမယ်</span></span>
<span class="line"><span>-&gt; username/repo ထည့်ထားရင် အဲဒီအတိုင်းသုံးပါမယ်</span></span>
<span class="line"><span>-&gt; ImgBed က dataset repository ကို check သို့မဟုတ် create လုပ်ပါမယ်</span></span>
<span class="line"><span>-&gt; test image upload လုပ်ပါ</span></span></code></pre></div>`,18)])])}const k=n(r,[["render",d]]);export{b as __pageData,k as default};
